"""Extensibility seams: room-selection Strategy, recurrence Strategy, Observer."""
from __future__ import annotations

from abc import ABC, abstractmethod
from datetime import timedelta

from models import Booking, MeetingRoom, TimeInterval


# ── WHY THIS CLASS: RoomSelectionStrategy ───────────────────────────────────
# When an employee says "just find me ANY free room", the rule for which room to
# pick varies by business need. We make that rule a swappable object so the
# orchestrator never hardcodes a policy.
# 🎙️ "Strategy seam — the service asks this interface to pick a room. Swapping
#     'first free' for 'smallest that fits' is a new class, no core change."
class RoomSelectionStrategy(ABC):
    @abstractmethod
    def select(self, rooms: list[MeetingRoom], interval: TimeInterval) -> MeetingRoom | None:
        ...


class FirstAvailableStrategy(RoomSelectionStrategy):
    def select(self, rooms, interval):
        return rooms[0] if rooms else None


class SmallestSufficientRoomStrategy(RoomSelectionStrategy):
    """Pick the smallest room that still fits the attendee count (less waste)."""
    def __init__(self, attendees: int) -> None:
        self.attendees = attendees

    def select(self, rooms, interval):
        fit = sorted((r for r in rooms if r.capacity >= self.attendees), key=lambda r: r.capacity)
        return fit[0] if fit else None


# ── WHY THIS CLASS: RecurrenceStrategy ──────────────────────────────────────
# Expands one base interval into a series (daily / weekly). Adding "monthly" is a
# new class, nothing else changes.
class RecurrenceStrategy(ABC):
    @abstractmethod
    def expand(self, base: TimeInterval, count: int) -> list[TimeInterval]:
        ...


class DailyRecurrence(RecurrenceStrategy):
    def expand(self, base, count):
        return [TimeInterval(base.start + timedelta(days=i), base.end + timedelta(days=i))
                for i in range(count)]


class WeeklyRecurrence(RecurrenceStrategy):
    def expand(self, base, count):
        return [TimeInterval(base.start + timedelta(weeks=i), base.end + timedelta(weeks=i))
                for i in range(count)]


# ── WHY THIS CLASS: BookingObserver ─────────────────────────────────────────
# The service shouts "confirmed!" / "cancelled!"; anyone who signed up reacts
# (email, Slack, calendar invite). Booking logic stays decoupled from notifying.
class BookingObserver(ABC):
    @abstractmethod
    def on_confirmed(self, booking: Booking) -> None: ...

    @abstractmethod
    def on_cancelled(self, booking: Booking) -> None: ...


class LoggingNotifier(BookingObserver):
    """Test/demo stand-in for a real email or Slack notifier."""
    def __init__(self) -> None:
        self.events: list[tuple[str, str]] = []

    def on_confirmed(self, booking):
        self.events.append(("CONFIRMED", booking.id))

    def on_cancelled(self, booking):
        self.events.append(("CANCELLED", booking.id))

